package org.apache.commons.math.optimization.linear;

import java.util.ArrayList;
import java.util.Collection;
import org.apache.commons.math.optimization.GoalType;
import org.apache.commons.math.optimization.OptimizationException;
import org.apache.commons.math.optimization.RealPointValuePair;

public class SimplexDebug extends SimplexSolver {

    public static void main(String[] args) throws OptimizationException {
        new SimplexDebug().run();
    }

    public void run() throws OptimizationException {
        LinearObjectiveFunction f = new LinearObjectiveFunction(new double[] { 0.2, 0.3 }, 0 );
        Collection<LinearConstraint> constraints = new ArrayList<LinearConstraint>();
        constraints.add(new LinearConstraint(new double[] { 1, 1 }, Relationship.EQ, 23.0));

        RealPointValuePair solution = this.optimize(f, constraints, GoalType.MAXIMIZE, true);
        System.out.println("Final Value: " + solution.getValue());
    }

    @Override
    protected void doIteration(final SimplexTableau tableau) throws OptimizationException {
        System.out.println("--- Iteration ---");
        printTableau(tableau);
        super.doIteration(tableau);
        System.out.println("--- After Iteration ---");
        printTableau(tableau);
    }

    @Override
    protected void solvePhase1(final SimplexTableau tableau) throws OptimizationException {
        System.out.println("--- Start Phase 1 ---");
        printTableau(tableau);
        super.solvePhase1(tableau);
        System.out.println("--- End Phase 1 ---");
        printTableau(tableau);
    }

    @Override
    public boolean isOptimal(final SimplexTableau tableau) {
        boolean optimal = super.isOptimal(tableau);
        System.out.println("isOptimal: " + optimal);
        return optimal;
    }

    private void printTableau(SimplexTableau tableau) {
        double[][] data = tableau.getData();
        for (int i = 0; i < data.length; i++) {
            for (int j = 0; j < data[i].length; j++) {
                System.out.printf("%8.4f ", data[i][j]);
            }
            System.out.println();
        }
        System.out.println("Objective Function Rows: " + tableau.getNumObjectiveFunctions());
        System.out.println("Artificial Variables: " + tableau.getNumArtificialVariables());
    }
}
